import translations from '../../translations';

/**
 * ModeIndicator - Manages the visibility and state of the mode indicator in the header.
 * Shows/hides completed-by information and provides a menu to toggle anonymization.
 */
export default class ModeIndicator {
  /**
   * Creates a ModeIndicator instance.
   * @param {Object} config - Configuration object
   * @param {Function} config.getUserInfo - Callback function to get user information
   */
  constructor({ getUserInfo }) {
    this.getUserInfo = getUserInfo;
    this.isAnonymized = false;
    this.isInitialized = false;
  }

  /**
   * Gets the current document language.
   * @returns {string} The language code (e.g., 'cs', 'en')
   */
  getCurrentLang() {
    return document.documentElement.lang || 'cs';
  }

  /**
   * Gets a translated string for the done/completed state.
   * @param {string} key - The translation key (e.g., 'completedBy', 'anonymizeName')
   * @param {string} lang - The language code
   * @returns {string} The translated text
   */
  getDoneTranslation(key, lang) {
    const item = translations.slideForm.done[key];
    return item[lang] || item.cs;
  }

  /**
   * Binds event listeners to the menu toggle and anonymize button.
   * Handles menu open/close and anonymization toggle actions.
   * @param {HTMLElement} modeIndicatorMenu - The menu container element
   * @param {HTMLElement} menuToggle - The arrow button that toggles the menu
   * @param {HTMLElement} anonymizeButton - The anonymize action button
   */
  bindEvents(modeIndicatorMenu, menuToggle, anonymizeButton) {
    // Toggle menu open/close when the menu toggle button is clicked
    menuToggle.addEventListener('click', (event) => {
      event.stopPropagation();
      const isOpen = modeIndicatorMenu.classList.toggle('is-open');
      menuToggle.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
    });

    // Toggle anonymization state when the anonymize button is clicked
    anonymizeButton.addEventListener('click', (event) => {
      event.preventDefault();
      this.isAnonymized = !this.isAnonymized;
      this.render();
      modeIndicatorMenu.classList.remove('is-open');
      menuToggle.setAttribute('aria-expanded', 'false');
    });

    // Close the menu when clicking outside of it
    document.addEventListener('click', (event) => {
      if (!modeIndicatorMenu.contains(event.target)) {
        modeIndicatorMenu.classList.remove('is-open');
        menuToggle.setAttribute('aria-expanded', 'false');
      }
    });
  }

  /**
   * Renders the mode indicator and menu.
   * Shows the indicator with current user info and optionally displays the anonymize menu.
   * Sets up event listeners on first render.
   */
  render() {
    const indicator = document.querySelector('.mode-indicator');
    const modeIndicatorMenu = document.querySelector('.mode-indicator-menu');
    const menuToggle = document.querySelector('.mode-indicator-menu-toggle');
    const anonymizeButton = document.querySelector('.mode-indicator-anonymize');

    if (!indicator) {
      return;
    }

    const lang = this.getCurrentLang();
    const translatedText = this.getDoneTranslation('completedBy', lang);
    const userInfo = this.isAnonymized ? '***' : this.getUserInfo();
    indicator.textContent = `${translatedText}: ${userInfo}`;
    indicator.style.display = 'block';

    if (!modeIndicatorMenu || !menuToggle || !anonymizeButton) {
      return;
    }

    modeIndicatorMenu.style.display = 'flex';

    if (!this.isInitialized) {
      this.bindEvents(modeIndicatorMenu, menuToggle, anonymizeButton);
      this.isInitialized = true;
    }

    const toggleLabel = this.isAnonymized
      ? this.getDoneTranslation('showName', lang)
      : this.getDoneTranslation('anonymizeName', lang);

    anonymizeButton.textContent = toggleLabel;
  }
}
